mapper.select:
SELECT mypage.my_page_id AS MYPAGE_ID, mypage.create_dt AS CREATE_DT, mypage.customer_no AS CUSTOMER_NO, customer.customer_name AS CUSTOMER_NAME, mypage.order_id AS ORDER_ID, mypage.region_nm AS REGION_NM, mypage.status AS STATUS, mypage.status_info AS STATUS_INFO, mypage.store_id AS STORE_ID, mypage.total_price AS TOTAL_PRICE, detail.order_detail_id AS DETAIL_ORDER_DETAIL_ID, detail.item_id AS DETAIL_ITEM_ID, detail.order_id AS DETAIL_ORDER_ID, detail.price_per_one AS DETAIL_PRICE_PER_ONE, detail.qty AS DETAIL_QTY FROM t_mypage mypage INNER JOIN t_customer customer ON customer.customer_no = mypage.customer_no LEFT JOIN t_mypage_order_detail detail ON detail.order_id = mypage.order_id WHERE 1=1
AND mypage.customer_no = #{customerNo}
AND mypage.create_dt BETWEEN #{startDateTime} AND #{endDateTime} ORDER BY mypage.store_id , mypage.order_id, detail.item_id

SELECT mypage.my_page_id, mypage.create_dt, mypage.customer_no, customer.customer_name, mypage.order_id, mypage.region_nm, mypage.status, mypage.status_info, mypage.store_id, mypage.total_price FROM t_mypage mypage INNER JOIN t_customer customer ON customer.customer_no = mypage.customer_no WHERE 1=1
AND mypage.customer_no = #{customerNo}
AND mypage.create_dt BETWEEN #{startDateTime} AND #{endDateTime} ORDER BY mypage.store_id , mypage.create_dt DESC

SELECT order_detail_id, item_id, order_id, price_per_one, qty FROM t_mypage_order_detail WHERE 1=1
AND order_id = #{orderId}
AND item_id IN
#{item}
ORDER BY item_id
